// src/components/Navbar.jsx
import { useState, useEffect } from "react";
import { Menu, X, Gauge } from "lucide-react";
import { useLanguage } from "../i18n/LanguageContext";

export default function Navbar() {
  const { lang, setLang, t } = useLanguage();
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const links = [
    { key: "home", href: "#hero" },
    { key: "about", href: "#about" },
    { key: "citycar", href: "#citycar" },
    { key: "beamng", href: "#beamng" },
    { key: "pricing", href: "#pricing" },
    { key: "contact", href: "#contact" },
  ];

  const LANGS = ["ru", "kz", "en"];
  const LANG_LABELS = { ru: "РУС", kz: "ҚАЗ", en: "ENG" };

  return (
    <nav
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        zIndex: 100,
        background: scrolled ? "rgba(255,255,255,0.97)" : "transparent",
        backdropFilter: scrolled ? "blur(12px)" : "none",
        borderBottom: scrolled ? "1px solid #E5E7EB" : "none",
        transition: "all 0.3s ease",
      }}
    >
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 24px", display: "flex", alignItems: "center", justifyContent: "space-between", height: 64 }}>
        {/* Logo */}
        <a href="#hero" style={{ display: "flex", alignItems: "center", gap: 10, textDecoration: "none" }}>
          <div style={{ width: 36, height: 36, background: "#1A1A2E", borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Gauge size={20} color="#E8C547" />
          </div>
          <div>
            <div style={{ fontFamily: "'DM Sans', sans-serif", fontWeight: 700, fontSize: 16, color: "#1A1A2E", letterSpacing: "-0.3px" }}>SimDrive.kz</div>
            <div style={{ fontSize: 10, color: "#6B7280", fontFamily: "'DM Sans', sans-serif", letterSpacing: "0.5px", textTransform: "uppercase" }}>Driving Academy</div>
          </div>
        </a>

        {/* Desktop Links */}
        <div style={{ display: "flex", alignItems: "center", gap: 32 }} className="desktop-nav">
          {links.map((link) => (
            <a
              key={link.key}
              href={link.href}
              style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: "#374151", textDecoration: "none", fontWeight: 500, transition: "color 0.2s" }}
              onMouseEnter={(e) => (e.target.style.color = "#1A1A2E")}
              onMouseLeave={(e) => (e.target.style.color = "#374151")}
            >
              {t.nav[link.key]}
            </a>
          ))}
        </div>

        {/* Language + CTA */}
        <div style={{ display: "flex", alignItems: "center", gap: 8 }} className="desktop-nav">
          <div style={{ display: "flex", background: "#F3F4F6", borderRadius: 8, padding: 3, gap: 2 }}>
            {LANGS.map((l) => (
              <button
                key={l}
                onClick={() => setLang(l)}
                style={{
                  padding: "4px 10px",
                  borderRadius: 6,
                  border: "none",
                  cursor: "pointer",
                  fontSize: 11,
                  fontWeight: 600,
                  fontFamily: "'DM Sans', sans-serif",
                  letterSpacing: "0.5px",
                  background: lang === l ? "#1A1A2E" : "transparent",
                  color: lang === l ? "#fff" : "#6B7280",
                  transition: "all 0.2s",
                }}
              >
                {LANG_LABELS[l]}
              </button>
            ))}
          </div>
          <a
            href="#contact"
            style={{
              padding: "8px 20px",
              background: "#1A1A2E",
              color: "#fff",
              borderRadius: 8,
              fontFamily: "'DM Sans', sans-serif",
              fontSize: 13,
              fontWeight: 600,
              textDecoration: "none",
              transition: "background 0.2s",
            }}
            onMouseEnter={(e) => (e.target.style.background = "#2D2D4E")}
            onMouseLeave={(e) => (e.target.style.background = "#1A1A2E")}
          >
            {t.nav.contact}
          </a>
        </div>

        {/* Mobile menu button */}
        <button
          className="mobile-menu-btn"
          onClick={() => setOpen(!open)}
          style={{ display: "none", background: "none", border: "none", cursor: "pointer", padding: 4 }}
        >
          {open ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Mobile Dropdown */}
      {open && (
        <div style={{ background: "#fff", borderTop: "1px solid #E5E7EB", padding: "16px 24px 24px" }}>
          {links.map((link) => (
            <a
              key={link.key}
              href={link.href}
              onClick={() => setOpen(false)}
              style={{ display: "block", padding: "10px 0", fontFamily: "'DM Sans', sans-serif", fontSize: 15, color: "#374151", textDecoration: "none", borderBottom: "1px solid #F3F4F6" }}
            >
              {t.nav[link.key]}
            </a>
          ))}
          <div style={{ display: "flex", gap: 8, marginTop: 16 }}>
            {LANGS.map((l) => (
              <button
                key={l}
                onClick={() => { setLang(l); setOpen(false); }}
                style={{
                  padding: "6px 14px",
                  borderRadius: 6,
                  border: "1px solid #E5E7EB",
                  cursor: "pointer",
                  fontSize: 12,
                  fontWeight: 600,
                  background: lang === l ? "#1A1A2E" : "#fff",
                  color: lang === l ? "#fff" : "#374151",
                }}
              >
                {LANG_LABELS[l]}
              </button>
            ))}
          </div>
        </div>
      )}

      <style>{`
        @media (max-width: 768px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: block !important; }
        }
      `}</style>
    </nav>
  );
}
